/**
 * Pure helpers for the External MCP card setup snippets.
 *
 * Generates client-specific JSON configuration blobs for Claude Code, Cursor,
 * and Windsurf. Used by the SetupInstructions sub-component.
 *
 * @module features/settings/lib/external-mcp-snippets
 */

/** Per-client setup snippet strings shown in the External MCP card. */
export interface ExternalMcpSnippets {
  claudeCode: string;
  claudeCodeCli: string;
  cursor: string;
  windsurf: string;
}

/**
 * Build per-client setup snippets for the external MCP endpoint.
 *
 * @param endpoint - Public URL of the DorkOS MCP server
 * @param apiKey - Bearer token; if null, a placeholder string is rendered so users see what to substitute
 */
export function buildSnippets(endpoint: string, apiKey: string | null): ExternalMcpSnippets {
  const authHeader = apiKey ? `Bearer ${apiKey}` : 'Bearer dork_mcp_YOUR_API_KEY';

  return {
    claudeCode: JSON.stringify(
      {
        mcpServers: {
          'dorkos-external': {
