              <Input
                id="mcp-max-requests"
                type="number"
                min={1}
                max={1000}
                value={rateLimit.maxPerWindow}
                onChange={(e) => {
                  const v = parseInt(e.target.value, 10);
                  if (v >= 1 && v <= 1000) onUpdate({ maxPerWindow: v });
                }}
